import{_ as i,o as s,c as t,a3 as e}from"./chunks/framework.DACwFHq9.js";const k=JSON.parse('{"title":"Kafka 监控与排障","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"middleware/kafka/troubleshooting.md","filePath":"middleware/kafka/troubleshooting.md","lastUpdated":1783394230000}'),l={name:"middleware/kafka/troubleshooting.md"};function n(r,a,o,d,p,h){return s(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="kafka-jian-kong-yu-pai-zhang" tabindex="-1">Kafka 监控与排障 <a class="header-anchor" href="#kafka-jian-kong-yu-pai-zhang" aria-label="Permalink to &quot;Kafka 监控与排障&quot;">​</a></h1><p>Kafka 排障要先判断问题发生在 Producer、Broker、Consumer 还是下游系统。不要只看 Consumer Lag，Lag 是结果，不是根因。</p><h2 id="he-xin-jian-kong-dui-xiang" tabindex="-1">核心监控对象 <a class="header-anchor" href="#he-xin-jian-kong-dui-xiang" aria-label="Permalink to &quot;核心监控对象&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>重点指标</th></tr></thead><tbody><tr><td>Producer</td><td>发送延迟、错误率、重试次数、缓冲区等待时间</td></tr><tr><td>Broker</td><td>请求延迟、网络线程、IO 线程、磁盘、ISR、Controller</td></tr><tr><td>Topic / Partition</td><td>写入速率、读取速率、分区倾斜、副本状态</td></tr><tr><td>Consumer</td><td>Lag、消费速率、Poll 间隔、提交失败</td></tr><tr><td>系统</td><td>CPU、内存、磁盘 IO、网络带宽、文件句柄</td></tr></tbody></table><h2 id="chang-yong-ming-ling" tabindex="-1">常用命令 <a class="header-anchor" href="#chang-yong-ming-ling" aria-label="Permalink to &quot;常用命令&quot;">​</a></h2><h3 id="cha-kan-topic-he-isr" tabindex="-1">查看 Topic 和 ISR <a class="header-anchor" href="#cha-kan-topic-he-isr" aria-label="Permalink to &quot;查看 Topic 和 ISR&quot;">​</a></h3><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-topics.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --describe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --topic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> orders</span></span></code></pre></div><p>重点看：</p><ul><li><code>Leader</code></li><li><code>Replicas</code></li><li><code>Isr</code></li><li>是否存在 Under-Replicated Partition</li></ul><h3 id="cha-kan-consumer-group" tabindex="-1">查看 Consumer Group <a class="header-anchor" href="#cha-kan-consumer-group" aria-label="Permalink to &quot;查看 Consumer Group&quot;">​</a></h3><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-consumer-groups.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --describe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --group</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> order-service</span></span></code></pre></div><p>重点看：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>CURRENT-OFFSET</code></td><td>当前已提交 Offset</td></tr><tr><td><code>LOG-END-OFFSET</code></td><td>Partition 最新 Offset</td></tr><tr><td><code>LAG</code></td><td>两者差值</td></tr><tr><td><code>CONSUMER-ID</code></td><td>当前消费实例</td></tr><tr><td><code>HOST</code></td><td>Consumer 所在主机</td></tr></tbody></table><h3 id="cha-kan-kraft-yuan-shu-ju" tabindex="-1">查看 KRaft 元数据 <a class="header-anchor" href="#cha-kan-kraft-yuan-shu-ju" aria-label="Permalink to &quot;查看 KRaft 元数据&quot;">​</a></h3><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-metadata-quorum.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --describe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --status</span></span></code></pre></div><p>重点看 Controller Quorum 是否稳定、Leader 是否频繁切换。</p><h2 id="consumer-lag-chi-xu-zeng-chang" tabindex="-1">Consumer Lag 持续增长 <a class="header-anchor" href="#consumer-lag-chi-xu-zeng-chang" aria-label="Permalink to &quot;Consumer Lag 持续增长&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LOG-END-OFFSET 增长速度 &gt; CURRENT-OFFSET 增长速度</span></span></code></pre></div><p>排查顺序：</p><ol><li>写入量是否突然升高</li><li>Consumer 实例是否减少或频繁 Rebalance</li><li>Partition 数是否限制了消费并行度</li><li>单条消息处理是否变慢</li><li>下游数据库、HTTP 服务、缓存是否变慢</li><li>Offset 是否提交失败</li></ol><p>处理方式：</p><table tabindex="0"><thead><tr><th>原因</th><th>处理</th></tr></thead><tbody><tr><td>写入峰值</td><td>临时扩容 Consumer，必要时增加 Partition</td></tr><tr><td>处理慢</td><td>优化业务逻辑、批量写下游、异步化</td></tr><tr><td>Partition 不足</td><td>扩分区后按 Key 分布评估顺序性影响</td></tr><tr><td>Rebalance 频繁</td><td>调整 <code>max.poll.interval.ms</code>、使用 Static Membership</td></tr><tr><td>下游慢</td><td>限流、降级、队列隔离</td></tr></tbody></table><h2 id="under-replicated-partition" tabindex="-1">Under-Replicated Partition <a class="header-anchor" href="#under-replicated-partition" aria-label="Permalink to &quot;Under-Replicated Partition&quot;">​</a></h2><p>Under-Replicated 表示副本没有全部跟上 Leader。</p><p>常见原因：</p><ul><li>Follower Broker 宕机</li><li>Broker 网络抖动</li><li>磁盘 IO 慢</li><li>副本拉取线程不足</li><li>单 Broker 负载过高</li></ul><p>排查：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-topics.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --describe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Isr&#39;</span></span></code></pre></div><p>观察 <code>Replicas</code> 和 <code>Isr</code> 是否数量不一致。</p><p>处理：</p><ul><li>恢复故障 Broker</li><li>检查磁盘空间和 IO Util</li><li>检查 Broker 间网络</li><li>适当增加 <code>num.replica.fetchers</code></li><li>重新分配热点 Partition</li></ul><h2 id="producer-fa-song-bian-man" tabindex="-1">Producer 发送变慢 <a class="header-anchor" href="#producer-fa-song-bian-man" aria-label="Permalink to &quot;Producer 发送变慢&quot;">​</a></h2><p>关注指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>含义</th></tr></thead><tbody><tr><td><code>request-latency-avg</code></td><td>请求平均延迟</td></tr><tr><td><code>record-error-rate</code></td><td>发送错误率</td></tr><tr><td><code>record-retry-rate</code></td><td>重试速率</td></tr><tr><td><code>bufferpool-wait-ratio</code></td><td>等待 Producer 缓冲区的比例</td></tr><tr><td><code>batch-size-avg</code></td><td>平均批次大小</td></tr></tbody></table><p>可能原因：</p><ul><li>Broker 端请求处理慢</li><li><code>acks=all</code> 下 ISR 同步慢</li><li>Producer 缓冲区太小</li><li><code>batch.size</code> / <code>linger.ms</code> 不合理</li><li>网络带宽不足</li><li>单 Partition 热点</li></ul><p>处理：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">buffer.memory</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=67108864</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">batch.size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=131072</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">linger.ms</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=5</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">compression.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=lz4</span></span></code></pre></div><p>如果是可靠性场景，不要为了降低延迟直接把 <code>acks</code> 从 <code>all</code> 改成 <code>1</code>，应先确认 ISR、磁盘、网络和批量配置。</p><h2 id="broker-qing-qiu-yan-chi-gao" tabindex="-1">Broker 请求延迟高 <a class="header-anchor" href="#broker-qing-qiu-yan-chi-gao" aria-label="Permalink to &quot;Broker 请求延迟高&quot;">​</a></h2><p>Broker 端通常看请求延迟拆分：</p><table tabindex="0"><thead><tr><th>阶段</th><th>含义</th></tr></thead><tbody><tr><td>Request Queue</td><td>请求等待网络线程处理</td></tr><tr><td>Local Time</td><td>Broker 本地处理时间</td></tr><tr><td>Remote Time</td><td>等待副本同步时间</td></tr><tr><td>Response Queue</td><td>响应等待网络线程发送</td></tr><tr><td>Response Send</td><td>响应发送耗时</td></tr></tbody></table><p>判断：</p><ul><li>Request Queue 高：网络线程不足或请求过多</li><li>Local Time 高：磁盘、页缓存、日志追加慢</li><li>Remote Time 高：Follower 同步慢，ISR 有问题</li><li>Response Queue 高：网络线程或网络带宽瓶颈</li></ul><h2 id="ci-pan-wen-ti" tabindex="-1">磁盘问题 <a class="header-anchor" href="#ci-pan-wen-ti" aria-label="Permalink to &quot;磁盘问题&quot;">​</a></h2><p>Kafka 对磁盘非常敏感，常见问题包括：</p><ul><li>磁盘空间不足</li><li>单盘热点</li><li>Page Cache 命中率下降</li><li>保留策略过大导致清理不及时</li><li>日志目录所在磁盘和系统盘混用</li></ul><p>检查方向：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iostat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsof</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> wc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span></span></code></pre></div><p>处理建议：</p><ul><li><code>log.dirs</code> 使用独立数据盘</li><li>合理设置 <code>log.retention.ms</code> 和 <code>log.retention.bytes</code></li><li>避免把超大保留周期和高写入 Topic 放在同一小磁盘</li><li>对热点 Topic 做分区和副本再分配</li></ul><h2 id="controller-yi-chang" tabindex="-1">Controller 异常 <a class="header-anchor" href="#controller-yi-chang" aria-label="Permalink to &quot;Controller 异常&quot;">​</a></h2><p>Controller 负责分区 Leader 选举和元数据管理。Controller 不稳定会导致：</p><ul><li>Leader 频繁切换</li><li>Topic 创建/删除变慢</li><li>Broker 上下线影响扩大</li><li>KRaft Quorum 不稳定</li></ul><p>排查：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-metadata-quorum.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --describe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --status</span></span></code></pre></div><p>关注：</p><ul><li>当前 Leader 是否频繁变化</li><li>Controller 节点是否资源不足</li><li>Broker 间网络是否稳定</li><li>元数据日志目录是否有磁盘问题</li></ul><h2 id="re-dian-partition" tabindex="-1">热点 Partition <a class="header-anchor" href="#re-dian-partition" aria-label="Permalink to &quot;热点 Partition&quot;">​</a></h2><p>现象：</p><ul><li>某个 Broker 流量明显高于其他 Broker</li><li>某个 Partition 的写入量远高于其他 Partition</li><li>Consumer Group 中某个 Consumer Lag 明显更高</li></ul><p>常见原因：</p><ul><li>Key 分布不均</li><li>所有消息使用固定 Key</li><li>Partition Leader 分布不均</li><li>某个大客户或大租户集中到同一 Key</li></ul><p>处理：</p><ul><li>优化 Key 设计，引入更均匀的分区键</li><li>增加 Partition 后评估顺序性影响</li><li>使用分区再分配工具迁移 Leader 和副本</li><li>对大租户拆 Topic 或拆业务流</li></ul><h2 id="pai-zhang-lu-jing" tabindex="-1">排障路径 <a class="header-anchor" href="#pai-zhang-lu-jing" aria-label="Permalink to &quot;排障路径&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问题现象</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── Producer 报错/发送慢？</span></span>
<span class="line"><span>  │     └── 看 ACK、重试、缓冲区、Broker 请求延迟</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── Consumer Lag 高？</span></span>
<span class="line"><span>  │     └── 看消费速率、Rebalance、下游处理、Partition 并行度</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── ISR 不完整？</span></span>
<span class="line"><span>  │     └── 看 Broker 存活、网络、磁盘、Follower 拉取</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └── 集群元数据异常？</span></span>
<span class="line"><span>        └── 看 Controller、KRaft Quorum、Broker 日志</span></span></code></pre></div><h2 id="can-kao" tabindex="-1">参考 <a class="header-anchor" href="#can-kao" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://kafka.apache.org/documentation/#operations" target="_blank" rel="noreferrer">Kafka Operations</a></li><li><a href="https://kafka.apache.org/documentation/#monitoring" target="_blank" rel="noreferrer">Kafka Monitoring</a></li><li><a href="https://kafka.apache.org/documentation/#basic_ops" target="_blank" rel="noreferrer">Kafka Tools</a></li></ul>`,69)])])}const u=i(l,[["render",n]]);export{k as __pageData,u as default};
